const crypto = require('crypto');

const vaultData = $('Vault: Signing Key').first().json;
const signing_key = vaultData?.data?.data?.payload_hmac_key;
if (!signing_key) {
  throw new Error('signing key not returned by vault — check vault-token-header credential scope');
}

const row = $input.first().json;
if (!row.partition_name) throw new Error('ensure_next_event_partition returned no row');

// range_start/range_end come back as ISO date strings; keep them as-is in canonical payload.
const payload = {
  partition_name: row.partition_name,
  range_start:    row.range_start,
  range_end:      row.range_end,
  was_created:    row.was_created === true || row.was_created === 't'
};

const canonical = JSON.stringify(payload, Object.keys(payload).sort());
const signature = crypto.createHmac('sha256', signing_key)
                        .update(canonical)
                        .digest('hex');

// Idempotency: one ensured-event per target partition month, regardless of how
// many times the workflow runs (cron + manual triggers + retries all collapse).
const monthKey = String(row.partition_name).replace(/^events_/, '');

return [{
  json: {
    event_type: 'partition.ensured',
    source: 'partition_maintenance',
    payload_json: JSON.stringify(payload),
    payload_signature: signature,
    idempotency_key: 'partition_ensured_' + monthKey,
    pipeline_version: '1.0',
    partition_name: row.partition_name,
    was_created: payload.was_created
  }
}];
